// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Poll work
	// (POST /v1/jobs/poll)
	PollWork(ctx context.Context, request PollWorkRequestObject) (PollWorkResponseObject, error)
	// Submit job
	// (POST /v1/tenants/{tenantId}/jobs)
	SubmitJob(ctx context.Context, request SubmitJobRequestObject) (SubmitJobResponseObject, error)
	// List jobs
	// (POST /v1/tenants/{tenantId}/jobs/query)
	ListJobs(ctx context.Context, request ListJobsRequestObject) (ListJobsResponseObject, error)
	// Submit restart job
	// (POST /v1/tenants/{tenantId}/jobs/restarts)
	SubmitRestartJob(ctx context.Context, request SubmitRestartJobRequestObject) (SubmitRestartJobResponseObject, error)
	// Get job
	// (GET /v1/tenants/{tenantId}/jobs/{jobId})
	GetJob(ctx context.Context, request GetJobRequestObject) (GetJobResponseObject, error)
	// Submit job with explicit job ID
	// (PUT /v1/tenants/{tenantId}/jobs/{jobId})
	PutJob(ctx context.Context, request PutJobRequestObject) (PutJobResponseObject, error)
	// Cancel job
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/cancel)
	CancelJob(ctx context.Context, request CancelJobRequestObject) (CancelJobResponseObject, error)
	// List chapters
	// (GET /v1/tenants/{tenantId}/jobs/{jobId}/chapters)
	ListChapters(ctx context.Context, request ListChaptersRequestObject) (ListChaptersResponseObject, error)
	// Get chapter
	// (GET /v1/tenants/{tenantId}/jobs/{jobId}/chapters/{ordinal})
	GetChapter(ctx context.Context, request GetChapterRequestObject) (GetChapterResponseObject, error)
	// Open artifact
	// (GET /v1/tenants/{tenantId}/jobs/{jobId}/chapters/{ordinal}/artifacts/{name})
	OpenArtifact(ctx context.Context, request OpenArtifactRequestObject) (OpenArtifactResponseObject, error)
	// Commit chapter if waiting
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/chapters/{ordinal}/commit-if-waiting)
	CommitChapterIfWaiting(ctx context.Context, request CommitChapterIfWaitingRequestObject) (CommitChapterIfWaitingResponseObject, error)
	// Get job lease
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/lease)
	GetJobLease(ctx context.Context, request GetJobLeaseRequestObject) (GetJobLeaseResponseObject, error)
	// Add chapter with lease
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/leases/{leaseId}/add_chapter)
	AddChapterWithLease(ctx context.Context, request AddChapterWithLeaseRequestObject) (AddChapterWithLeaseResponseObject, error)
	// Complete job with lease
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/leases/{leaseId}/complete)
	CompleteJobWithLease(ctx context.Context, request CompleteJobWithLeaseRequestObject) (CompleteJobWithLeaseResponseObject, error)
	// Keep lease alive
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/leases/{leaseId}/keepalive)
	KeepAliveLease(ctx context.Context, request KeepAliveLeaseRequestObject) (KeepAliveLeaseResponseObject, error)
	// Reschedule job with lease
	// (POST /v1/tenants/{tenantId}/jobs/{jobId}/leases/{leaseId}/reschedule)
	RescheduleJobWithLease(ctx context.Context, request RescheduleJobWithLeaseRequestObject) (RescheduleJobWithLeaseResponseObject, error)
	// Submit restart job with explicit job ID
	// (PUT /v1/tenants/{tenantId}/jobs/{jobId}/restart)
	PutRestartJob(ctx context.Context, request PutRestartJobRequestObject) (PutRestartJobResponseObject, error)
	// List schedules
	// (POST /v1/tenants/{tenantId}/schedules/query)
	ListSchedules(ctx context.Context, request ListSchedulesRequestObject) (ListSchedulesResponseObject, error)
	// Get schedule
	// (GET /v1/tenants/{tenantId}/schedules/{scheduleId})
	GetSchedule(ctx context.Context, request GetScheduleRequestObject) (GetScheduleResponseObject, error)
	// Upsert schedule
	// (PUT /v1/tenants/{tenantId}/schedules/{scheduleId})
	UpsertSchedule(ctx context.Context, request UpsertScheduleRequestObject) (UpsertScheduleResponseObject, error)
	// Archive schedule
	// (POST /v1/tenants/{tenantId}/schedules/{scheduleId}/archive)
	ArchiveSchedule(ctx context.Context, request ArchiveScheduleRequestObject) (ArchiveScheduleResponseObject, error)
	// Pause schedule
	// (POST /v1/tenants/{tenantId}/schedules/{scheduleId}/pause)
	PauseSchedule(ctx context.Context, request PauseScheduleRequestObject) (PauseScheduleResponseObject, error)
	// Resume schedule
	// (POST /v1/tenants/{tenantId}/schedules/{scheduleId}/resume)
	ResumeSchedule(ctx context.Context, request ResumeScheduleRequestObject) (ResumeScheduleResponseObject, error)
	// List schedule runs
	// (POST /v1/tenants/{tenantId}/schedules/{scheduleId}/runs/query)
	ListScheduleRuns(ctx context.Context, request ListScheduleRunsRequestObject) (ListScheduleRunsResponseObject, error)
	// Trigger schedule now
	// (POST /v1/tenants/{tenantId}/schedules/{scheduleId}/trigger)
	TriggerSchedule(ctx context.Context, request TriggerScheduleRequestObject) (TriggerScheduleResponseObject, error)
	// List job schemas
	// (GET /v1/tenants/{tenantId}/schemas)
	ListJobSchemas(ctx context.Context, request ListJobSchemasRequestObject) (ListJobSchemasResponseObject, error)
	// Register job schema
	// (POST /v1/tenants/{tenantId}/schemas)
	RegisterJobSchema(ctx context.Context, request RegisterJobSchemaRequestObject) (RegisterJobSchemaResponseObject, error)
	// Get job schema
	// (GET /v1/tenants/{tenantId}/schemas/{schemaHash})
	GetJobSchema(ctx context.Context, request GetJobSchemaRequestObject) (GetJobSchemaResponseObject, error)
	// Archive job schema
	// (POST /v1/tenants/{tenantId}/schemas/{schemaHash}/archive)
	ArchiveJobSchema(ctx context.Context, request ArchiveJobSchemaRequestObject) (ArchiveJobSchemaResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

